        "id": "alaska-snap-food-benefits",
        "name": "Supplemental Nutrition Assistance Program (SNAP)",
        "shortName": "Alaska SNAP",
        "tagline": "Monthly grocery benefits for parents on fixed incomes — Alaska offers higher income limits than most states.",
