        "intro": "If your parent is 55+ and unemployed with very low income, Alaska's MASST program provides part-time paid work while they search for permanent employment. Your parent earns minimum wage for 20 hours per week at community service positions with nonprofits, government agencies, or Native organizations while receiving job training and placement assistance.\n\nThis is a bridge program designed to help older Alaskans gain skills and work experience to find unsubsidized employment. Because MASST combines paid work experience with active job search support, participants develop both income and employment prospects. The program operates statewide through regional coordinators who match participants with local organizations.\n\nCritical limitation: Your parent can only participate for 48 months total in their lifetime — no extensions or waivers. Income must be at or below 125% of the federal poverty level, which is significantly below median household income.",
        "savingsRange": "",
        "savingsSource": "Part-time employment at minimum wage",
        "savingsVerified": false,
        "structuredEligibility": {
          "summary": [
            "Age 55+",
            "Unemployed",
            "Income at 125% poverty level",
            "Poor employment prospects"
          ],
          "ageRequirement": "55+",
          "incomeTable": null,
          "assetLimits": null,
          "functionalRequirement": null,
          "otherRequirements": [
            "Must be unemployed",
            "Must have poor employment prospects",
            "Priority given to veterans, those 65+, those with disabilities, limited English proficiency, rural residents, homeless individuals"
          ],
          "povertyLevelReference": "125% FPL"
        },
        "applicationGuide": {
          "method": "in-person",
          "summary": "Apply in-person at any Alaska Job Center Network location — processing time not specified.",
          "steps": [
            {
              "step": 1,
              "title": "Visit Alaska Job Center",
              "description": "Go to your nearest Alaska Job Center Network (AJCN) location to meet with a counselor about MASST eligibility."
            },
            {
              "step": 2,
              "title": "Income verification",
              "description": "Bring documentation showing your parent's household income is at or below 125% of federal poverty level."
            },
            {
              "step": 3,
              "title": "Enrollment assessment",
              "description": "Staff will assess employment prospects and determine priority placement based on veteran status, age 65+, disability, or other priority factors."
            },
            {
              "step": 4,
              "title": "Receive durational limits form",
              "description": "You'll receive Alaska SCSEP Durational Limits Form explaining the 48-month lifetime participation limit."
            }
          ],
          "processingTime": null,
          "waitlist": null,
          "tip": "Veterans, those 65+, and those with disabilities get priority — mention these qualifications upfront.",
          "urls": []
        },
        "contentSections": [
          {
            "type": "callout",
            "tone": "warning",
            "text": "48-month lifetime limit: Your parent can never participate again once they reach 48 months total. No waivers or extensions available."
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "This is temporary bridge employment, not permanent work. Your parent must actively job search for unsubsidized employment throughout the program."
          }
        ],
        "faqs": [
          {
            "question": "How much will my parent earn per week?",
            "answer": "Your parent will work an average of 20 hours per week at the highest of federal, state, or local minimum wage. This provides part-time income while they search for permanent employment."
          },
          {
            "question": "What happens if my parent can't find regular employment before the 48-month limit?",
            "answer": "They must leave the program at 48 months regardless of employment status. There are no waivers or extensions. The program provides job placement assistance throughout participation to help avoid this situation."
          },
          {
            "question": "Can my parent choose where they work?",
            "answer": "Placements are made with nonprofits, government agencies, or Native organizations in your region. Regional coordinators match participants with available positions based on skills and local opportunities."
          },
          {
            "question": "What if my parent's income is just slightly over the 125% poverty level limit?",
            "answer": "Income limits are strict with no exceptions. If household income exceeds 125% of federal poverty level, your parent won't qualify. The program targets those with very limited financial resources."
          },
          {
            "question": "Will this affect my parent's Social Security or other benefits?",
            "answer": "MASST provides earned income from employment, which may affect other benefits. Contact Social Security Administration or relevant benefit programs to understand impacts before enrolling."
          },
          {
            "question": "What kind of job training is included?",
            "answer": "Training includes computer skills, vocational skills relevant to the work placement, and job search assistance. The goal is building skills that transfer to unsubsidized employment in your parent's community."
          }
        ],
        "phone": null,
        "sourceUrl": "https://labor.alaska.gov/masst/about-masst.htm",
        "contentStatus": "pipeline-draft",
        "draftedAt": "2026-04-09"
