        "id": "california-weatherization-assistance-program",
        "name": "Weatherization Assistance Program (WAP)",
        "shortName": "Weatherization Assistance",
        "tagline": "Free home weatherization improvements to cut your parent's energy bills and make their home safer",
        "programType": "benefit",
        "complexity": "deep",
        "geographicScope": {
          "type": "federal",
          "stateVariation": true,
          "localEntities": [
            {
              "name": "Local low-income energy services providers via CSD; CSET; 211 LA services; PG&E/SCE for related assessments",
              "type": "service-area"
            }
          ]
        },
        "intro": "If your parent's energy bills are eating into their fixed income, they may qualify for free home improvements that cut those costs permanently. The Weatherization Assistance Program provides insulation, air sealing, furnace repairs or replacement, and other energy efficiency upgrades at no cost to qualifying homeowners, renters, and mobile home residents.\n\nYour parent qualifies if their household income is at or below 200% of federal poverty guidelines, or if they receive SSI (which automatically qualifies them regardless of other income). Priority goes to households with adults 60+, so your parent may move up the waitlist faster than younger applicants.\n\nBecause local providers handle applications and each has different wait times and requirements, you'll need to contact the agency in your parent's area to start the process. An energy specialist will assess their home to determine which improvements will save the most on heating and cooling costs.",
        "savingsRange": "",
        "savingsSource": "Free service",
