        "contentSections": [
          {
            "type": "callout",
            "tone": "tip",
            "text": "This program only handles civil legal matters, not criminal cases. If your parent has been charged with a crime, contact a criminal defense attorney instead."
          }
        ],
        "faqs": [
          {
            "question": "What if my parent's income is too high for other assistance programs?",
            "answer": "Income doesn't disqualify your parent from legal services. While some counties prioritize low-income seniors, the program is available regardless of income level statewide."
          },
          {
            "question": "Can they help with a will even if my parent has assets?",
            "answer": "Yes, most providers offer simple wills and advance directives regardless of asset level. For complex estates, they may refer you to a private attorney but can often handle basic planning documents."
          },
          {
            "question": "My parent is being evicted — how quickly can they get help?",
            "answer": "Call immediately. Eviction cases move fast, and many providers prioritize housing emergencies. Some offer same-day phone consultations for urgent matters."
          },
          {
            "question": "What if Medicare denied my parent's claim and the appeal deadline is approaching?",
            "answer": "Legal services can help with Medicare and Medi-Cal appeals. Call as soon as possible — appeal deadlines are strict and missing them can cost your parent thousands in coverage."
          },
          {
            "question": "Can they represent my parent in court?",
            "answer": "It depends on your county's provider and the case type. Some offer full representation, others provide advice and help with paperwork. The intake worker will explain what level of help they can provide."
          },
          {
            "question": "My parent is 58 but has disabilities — do they qualify?",
            "answer": "Possibly. Some counties serve adults with disabilities under 60. Contact your local Area Agency on Aging to ask about their specific age requirements."
          }
        ],
