        {
          "name": "Medi-Cal Medicare Savings Programs",
          "programId": "medicare-savings-programs",
          "why": "Covers Medicare premiums and copays if your parent's income is under $1,762/month."
        },
        {
          "name": "CalFresh",
          "programId": "calfresh",
          "why": "Provides up to $291 monthly for groceries with no asset limits for seniors 60+."
        }
