          "steps": [
            {
              "step": 1,
              "title": "Call Elder Helpline",
              "description": "Call 1-800-96-ELDER (800-963-5337) to reach your local Aging and Disability Resource Center (ADRC)"
            },
            {
              "step": 2,
              "title": "Complete assessment",
              "description": "A local program staff member will assess your parent's needs, either by phone or in-person visit"
            },
            {
              "step": 3,
              "title": "Provide documentation",
              "description": "Submit proof of age, residence, and any medical information about dietary restrictions or health conditions"
            },
            {
              "step": 4,
              "title": "Wait for approval",
              "description": "Your parent will be placed on the program roster or waitlist depending on local availability and priority level"
            }
          ],
          "processingTime": "Varies by county — some programs start within a week, others have longer waitlists",
          "waitlist": "Common in most local programs; varies by region and demand",
          "tip": "If your parent has Medicaid long-term care coverage, contact their case manager directly as they may have faster access to meal benefits",
          "urls": [
            {
              "label": "Florida Department of Elder Affairs Food Assistance",
              "url": "https://elderaffairs.org/programs-and-services/food-assistance/"
            }
          ]
