        "id": "north-dakota-basic-care-assistance-bcap",
        "name": "Basic Care Assistance Program (BCAP)",
        "shortName": "BCAP",
        "tagline": "Helps pay room and board costs if your parent lives in a basic care facility and doesn't qualify for full Medicaid.",
        "programType": "benefit",
        "complexity": "deep",
