        "name": "New Hampshire Medicaid (Nursing Home Medicaid for seniors)",
        "shortName": "Nursing Home Medicaid",
        "tagline": "If your parent needs nursing home care but can't afford it, this covers the full cost after they contribute most of their income.",
        "programType": "benefit",
