      {
        "id": "oklahoma-medicare-savings-program",
        "name": "Medicare Savings Program",
        "shortName": "Medicare Savings",
        "tagline": "If your parent's Medicare costs are straining their budget, this program can eliminate premiums and cut drug costs to $12.65 per prescription.",
        "programType": "benefit",
        "complexity": "deep",
        "geographicScope": {
          "type": "federal",
          "stateVariation": true,
          "localEntities": [
            {
              "name": "Local OKDHS Human Services Centers statewide.",
              "type": "service-area"
            }
          ]
        },
        "intro": "If your parent struggles to afford Medicare premiums, deductibles, or prescription drugs, Oklahoma's Medicare Savings Program can eliminate these costs entirely. The program has four tiers — the lowest tier (QMB) covers all Medicare premiums, deductibles, and coinsurance, while higher tiers cover at least Medicare Part B premiums. All tiers also provide Extra Help for prescription drugs, capping costs at $12.65 per medication in 2026.\n\nTypical savings run around $185 monthly, though this varies by tier and your parent's Medicare usage. Because Oklahoma has strict asset limits (around $2,000 for individuals, $3,000 for couples in lower tiers), this program works best for parents with limited savings but whose income falls just above Medicaid limits.",
        "savingsRange": "$2,220/year",
        "savingsSource": "Based on ~$185 monthly savings example from program data",
        "savingsVerified": false,
        "structuredEligibility": {
          "summary": [
            "Must have Medicare Part A",
            "Income varies by tier (example: $1,215/month for lowest tier)",
            "Assets under $2,000-$9,660 depending on tier",
            "Oklahoma resident"
          ],
          "ageRequirement": null,
          "incomeTable": null,
          "assetLimits": {
            "individual": 2000,
            "couple": 3000,
            "countedAssets": [
              "Checking and savings accounts",
              "CDs",
              "Life insurance cash value",
              "Stocks and bonds",
              "Real estate (excluding home)"
            ],
            "exemptAssets": [
              "Primary home",
              "Household furnishings",
              "One car",
              "Pre-paid funeral trusts up to $10,000"
            ],
            "homeEquityCap": null
          },
          "functionalRequirement": null,
          "otherRequirements": [
            "Must be eligible for Medicare Part A (even if not enrolled)",
            "Part B required for SLMB and QI tiers",
            "Oklahoma residency"
          ],
          "povertyLevelReference": "Up to 135% FPL for highest tier"
        },
        "applicationGuide": {
          "method": "multiple",
          "summary": "Apply at your local OKDHS Human Services Center or call the Senior Health Insurance Counseling line — processing time not specified but QI tier is first-come, first-served.",
          "steps": [
            {
              "step": 1,
              "title": "Gather Medicare and financial documents",
              "description": "You'll need proof of Medicare Parts A and B, income statements, and bank statements. Important: Add back any Medicare Part B premium deducted from Social Security — this doesn't count toward income limits."
            },
            {
              "step": 2,
              "title": "Contact your local OKDHS center or call the state helpline",
              "description": "Visit your nearest OKDHS Human Services Center in person, or call Oklahoma Insurance Department Senior Health Insurance Counseling at 800-763-2828."
            },
            {
              "step": 3,
              "title": "Let the state determine your tier",
              "description": "Oklahoma will place your parent in the highest tier they qualify for — you don't need to choose. They may qualify for a higher tier than expected."
            }
          ],
          "processingTime": "Not specified",
          "waitlist": "QI tier may have waitlist due to federal funding caps — apply even if unsure about qualification",
          "tip": "Income limits update every April, so check current limits in OKDHS Appendix C-1 before applying.",
          "urls": [
            {
              "label": "OKDHS Health Help Programs",
              "url": "https://oklahoma.gov/okdhs/services/health/help.html"
            }
          ]
        },
        "contentSections": [
          {
            "type": "tier-comparison",
            "heading": "Program Tiers and Coverage",
            "tiers": [
              {
                "name": "QMB (Qualified Medicare Beneficiary)",
                "description": "Lowest income tier",
                "incomeLimit": "Example: $1,215/month individual, $1,643/month couple",
                "coverage": "Medicare Part A premiums (if applicable), Part B premiums and deductible, all coinsurance and deductibles, plus Extra Help for drugs"
              },
              {
                "name": "SLMB (Specified Low-Income Medicare Beneficiary)",
                "description": "Higher income tier",
                "incomeLimit": "Higher than QMB (exact limits in OKDHS Appendix C-1)",
                "coverage": "Medicare Part B premiums plus Extra Help for drugs"
              },
              {
                "name": "QI (Qualifying Individual)",
                "description": "Highest income tier (up to 135% FPL)",
                "incomeLimit": "Example: up to ~$1,763/month individual, $2,380/month couple",
                "coverage": "Medicare Part B premiums plus Extra Help (drugs capped at $12.65 each in 2026)"
              },
              {
                "name": "QDWI (Qualified Disabled & Working Individual)",
                "description": "For working disabled individuals",
                "incomeLimit": "Varies (see OKDHS Appendix C-1)",
                "coverage": "Medicare Part A premiums only"
              }
            ]
          },
          {
            "type": "what-counts",
            "heading": "Asset Limits: What Counts",
            "included": [
              "Checking and savings accounts",
              "Certificates of deposit (CDs)",
              "Life insurance cash value",
              "Stocks and bonds",
              "Real estate other than primary home"
            ],
            "excluded": [
              "Primary home (any value)",
              "Household furnishings and personal belongings",
              "One car (any value)",
              "Pre-paid funeral trusts up to $10,000"
            ]
          },
          {
            "type": "documents",
            "heading": "What to Bring",
            "categories": [
              {
                "name": "Medicare Proof",
                "items": [
                  "Medicare card showing Parts A and B",
                  "Medicare enrollment documentation"
                ]
              },
              {
                "name": "Financial",
                "items": [
                  "Social Security statements (add back Part B premium)",
                  "Bank statements for all accounts",
                  "Pay stubs if working (over half of employment income excluded)",
                  "Documentation of all assets and investments"
                ]
              },
              {
                "name": "Identity",
                "items": [
                  "Photo ID",
                  "Proof of Oklahoma residency"
                ]
              }
            ]
          },
          {
            "type": "callout",
            "tone": "warning",
            "text": "QI tier requires annual reapplication and is first-come, first-served with funding caps. If your parent qualified before, they get priority, but apply early when renewal opens."
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "When calculating income, remember to add back the Medicare Part B premium deducted from Social Security — this doesn't count toward the income limit. Also, if your parent works, over half of employment income is excluded."
          }
        ],
        "faqs": [
          {
            "question": "Can Mom keep her house if she qualifies for this program?",
            "answer": "Yes. Your parent's primary home doesn't count toward asset limits regardless of value. They can also keep one car, household furnishings, and pre-paid funeral trusts up to $10,000."
          },
          {
            "question": "What if Dad's income is just over the limit?",
            "answer": "Income limits update every April, and there are four different tiers with different limits. Oklahoma will automatically place him in the highest tier he qualifies for. Also remember that if he works, over half of employment income doesn't count toward limits."
          },
          {
            "question": "Does this replace Medicare or give Mom full Medicaid?",
            "answer": "No, this works alongside Medicare. Your parent keeps their regular Medicare coverage, but the state pays their premiums, deductibles, and coinsurance (depending on tier). It's not full Medicaid with long-term care coverage."
          },
          {
            "question": "How much will this actually save on prescriptions?",
            "answer": "All tiers include Extra Help for prescription drugs. In 2026, this caps costs at $12.65 per medication. The exact savings depend on what medications your parent currently takes and their current Medicare drug plan."
          },
          {
            "question": "What happens if Mom gets denied but her situation changes?",
            "answer": "She can reapply anytime her income or assets change. Income limits also update every April, so someone who didn't qualify one year might qualify the next. The QI tier has annual reapplication anyway."
          },
          {
            "question": "If Dad is married but Mom doesn't need this program, how do asset limits work?",
            "answer": "Oklahoma has spousal protection rules. The spouse who doesn't need the program can keep up to $148,620 in assets. This prevents couples from having to impoverish both spouses for one to qualify."
          }
        ],
        "phone": "800-763-2828",
        "sourceUrl": "https://oklahoma.gov/okdhs/services/health/help.html",
        "contentStatus": "pipeline-draft",
        "draftedAt": "2026-04-09"
      }
