      {
        "id": "oregon-pace-elderly-care",
        "name": "Program of All-Inclusive Care for the Elderly (PACE)",
        "shortName": "PACE",
        "tagline": "Complete medical and long-term care under one program with no deductibles or copays if your parent needs nursing facility level care.",
        "programType": "benefit",
        "complexity": "deep",
        "geographicScope": {
          "type": "local",
          "stateVariation": false,
          "localEntities": [
            {
              "name": "Providence ElderPlace (Multnomah, Clackamas, Washington, Clatsop counties)",
              "type": "service-area"
            },
            {
              "name": "Other PACE organizations in Oregon (exact list not in sources; contact ODHS or local AAA)",
              "type": "service-area"
            }
          ]
        },
        "intro": "If your parent needs nursing facility level care but wants to stay in the community, PACE provides everything under one program: primary care, specialists, prescription drugs, adult day services, therapy, in-home care, and even nursing home care if needed. Because all care goes through one interdisciplinary team, your parent won't need to coordinate between separate providers — the PACE team manages everything.\n\nPACE is completely free for parents eligible for Medicaid. Parents with Medicare only pay a monthly premium (amount varies by provider). Your parent must be 55+ and assessed at Oregon's nursing facility level of care (Service Priority Level 1-13), which means they need daily help with activities like bathing, dressing, or medication management.\n\nThe biggest requirement: your parent must use only PACE providers for all medical care. No outside doctors or hospitals. PACE is only available in specific service areas — primarily around Portland through Providence ElderPlace.",
        "savingsRange": "",
        "savingsSource": "Free service",
        "savingsVerified": true,
        "structuredEligibility": {
          "summary": [
            "Age 55+",
            "Need nursing facility level care",
            "Live in PACE service area",
            "Use only PACE providers",
            "No income limits"
          ],
          "ageRequirement": "55+",
          "incomeTable": null,
          "assetLimits": null,
          "functionalRequirement": "Must be assessed at nursing facility level of care (Oregon Service Priority Level 1-13) — meaning your parent needs daily help with bathing, dressing, medication management, or similar care",
          "otherRequirements": [
            "Must live in a PACE-approved service area",
            "Must agree to receive all medical and long-term care exclusively from PACE providers",
            "Must be able to live safely in the community with PACE services",
            "Cannot require enhanced care at Oregon State Hospital",
            "Cannot need Medicare skilled care with no community discharge expected within 30 days"
          ],
          "povertyLevelReference": null
        },
        "applicationGuide": {
          "method": "phone",
          "summary": "Contact your local PACE organization's intake specialists for screening and enrollment — processing time not specified.",
          "steps": [
            {
              "step": 1,
              "title": "Find your local PACE provider",
              "description": "Determine which PACE organization serves your parent's area. Providence ElderPlace covers Multnomah, Clackamas, Washington, and Clatsop counties."
            },
            {
              "step": 2,
              "title": "Call intake specialists",
              "description": "Contact the PACE provider directly for initial screening. Each organization handles its own enrollment process."
            },
            {
              "step": 3,
              "title": "Complete nursing facility assessment",
              "description": "Your parent will be assessed to confirm they meet Oregon's nursing facility level of care (Service Priority Level 1-13)."
            },
            {
              "step": 4,
              "title": "Verify service area residency",
              "description": "Provide documentation that your parent lives in the PACE organization's approved service area."
            },
            {
              "step": 5,
              "title": "Determine payment method",
              "description": "If Medicaid-eligible, services are free. If Medicare-only, you'll pay a monthly premium. Private pay available for those with neither."
            }
          ],
          "processingTime": null,
          "waitlist": null,
          "tip": "Before applying, confirm your parent is willing to switch all their medical care to PACE providers only — they cannot keep their current doctors.",
          "urls": []
        },
        "contentSections": [
          {
            "type": "documents",
            "heading": "What to Bring",
            "categories": [
              {
                "name": "Care Assessment",
                "items": [
                  "Documentation for nursing facility level of care assessment (Service Priority Level 1-13)",
                  "Current medical records showing need for daily care assistance"
                ]
              },
              {
                "name": "Residency",
                "items": [
                  "Proof of residency in PACE service area",
                  "Utility bills or lease agreement showing address"
                ]
              },
              {
                "name": "Insurance Status",
                "items": [
                  "Medicare card if applicable",
                  "Medicaid documentation if eligible",
                  "Income documentation if paying privately"
                ]
              }
            ]
          },
          {
            "type": "county-directory",
            "heading": "PACE Providers",
            "offices": [
              {
                "name": "Providence ElderPlace",
                "type": "service-area",
                "phone": null,
                "address": "Serves Multnomah, Clackamas, Washington, and Clatsop counties"
              },
              {
                "name": "Other PACE Organizations",
                "type": "service-area",
                "phone": null,
                "address": "Contact Oregon Department of Human Services or your local Area Agency on Aging for providers in other areas"
              }
            ]
          },
          {
            "type": "callout",
            "tone": "warning",
            "text": "PACE is only available in specific service areas and your parent must live there to qualify. If they live outside a PACE service area, they cannot enroll even if they meet all other requirements."
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "Your parent must agree to use ONLY PACE providers for all medical care — no outside doctors, specialists, or hospitals. This is the biggest adjustment for most families but allows PACE to coordinate all care seamlessly."
          }
        ],
        "faqs": [
          {
            "question": "Can my parent keep their current doctor if they join PACE?",
            "answer": "No. Your parent must receive all medical and long-term care exclusively from PACE providers. They cannot see outside doctors, specialists, or use other hospitals once enrolled."
          },
          {
            "question": "What if my parent has Medicare but not Medicaid — how much will PACE cost?",
            "answer": "Parents with Medicare only pay a monthly premium, but the exact amount varies by PACE provider and isn't specified in available sources. Contact your local PACE organization for current premium rates."
          },
          {
            "question": "Can my parent live in their own home with PACE services?",
            "answer": "Yes, as long as they can live safely in the community with PACE services. Your parent can receive care in their own home, at community-based care facilities, or at PACE health centers."
          },
          {
            "question": "What happens if my parent needs nursing home care while in PACE?",
            "answer": "PACE covers nursing home care if needed, but only at facilities within the PACE network. The interdisciplinary team will coordinate this transition as part of your parent's overall care plan."
          },
          {
            "question": "Does my parent have to go to adult day services through PACE?",
            "answer": "PACE includes adult day services, but participation depends on your parent's individual care plan developed by the interdisciplinary team. Not all PACE participants use every service."
          },
          {
            "question": "What if we move to a different county — can my parent stay in PACE?",
            "answer": "Your parent can only receive PACE services in their organization's approved service area. Moving outside this area means they would need to find a different PACE provider in the new location or leave the program."
          }
        ],
        "phone": null,
        "sourceUrl": "https://www.oregon.gov/odhs/providers-partners/seniors-disabilities/Documents/pace-fact-sheet.pdf",
        "contentStatus": "pipeline-draft",
        "draftedAt": "2026-04-09"
      }
