      {
        "id": "virginia-medicare-savings-programs",
        "name": "Medicare Savings Programs (QMB, SLMB, QI)",
        "shortName": "Medicare Savings",
        "tagline": "If your parent struggles with Medicare premiums and deductibles, they may qualify for help paying $1,000–4,000+ annually in Medicare costs.",
        "programType": "benefit",
        "complexity": "deep",
        "geographicScope": {
          "type": "federal",
          "stateVariation": true,
          "localEntities": [
            {
              "name": "Local Department of Social Services offices (locator: dss.virginia.gov/localagency)",
              "type": "service-area"
            }
          ]
        },
        "intro": "If your parent is on Medicare and struggling with premiums, deductibles, or copays, three Virginia programs can help pay these costs. The Qualified Medicare Beneficiary (QMB) program covers all Medicare cost-sharing including premiums, deductibles, and copays. The Specified Low-Income Medicare Beneficiary (SLMB) and Qualifying Individual (QI) programs cover Medicare Part B premiums only — saving roughly $1,980 per year in 2026.\n\nThese programs have different income limits: QMB for those earning up to about $1,350/month ($1,824/month for couples), SLMB up to roughly $1,620/month single, and QI up to about $1,823/month single. Because you qualify based on income level, your parent automatically gets Extra Help with prescription drug costs too.\n\nYou must apply through your local Virginia Department of Social Services office — there's no statewide online application. The QI program has limited federal funding and may have waitlists.",
        "savingsRange": "$1,980 – $4,000+/year in 2026",
        "savingsSource": "Medicare Part B premiums plus deductibles and copays for QMB enrollees",
        "savingsVerified": true,
        "structuredEligibility": {
          "summary": [
            "Must have Medicare Part A",
            "Income below $1,350-1,823/month (single)",
            "Assets below $9,660 (single)"
          ],
          "ageRequirement": null,
          "incomeTable": [
            {
              "householdSize": 1,
              "monthlyLimit": 1350
            },
            {
              "householdSize": 2,
              "monthlyLimit": 1824
            }
          ],
          "assetLimits": {
            "individual": 9660,
            "couple": 14470,
            "countedAssets": [
              "Checking and savings accounts",
              "Stocks and bonds",
              "CDs and investment accounts"
            ],
            "exemptAssets": [
              "Primary home",
              "One vehicle",
              "Burial plot",
              "Up to $3,500 for burial expenses"
            ],
            "homeEquityCap": null
          },
          "functionalRequirement": null,
          "otherRequirements": [
            "Must be entitled to Medicare Part A",
            "Must have Medicare Part B for SLMB/QI programs",
            "U.S. citizen or qualified immigrant",
            "Virginia resident"
          ],
          "povertyLevelReference": "100-135% FPL"
        },
        "applicationGuide": {
          "method": "in-person",
          "summary": "Apply at your local Virginia Department of Social Services office — typically takes 45 days to process.",
          "steps": [
            {
              "step": 1,
              "title": "Find your local DSS office",
              "description": "Use the office locator at dss.virginia.gov/localagency to find your parent's local Department of Social Services office."
            },
            {
              "step": 2,
              "title": "Gather required documents",
              "description": "Collect proof of income (Social Security awards, bank statements), Medicare card showing Parts A and B, and asset documentation."
            },
            {
              "step": 3,
              "title": "Complete the MEDS application",
              "description": "Fill out the Medicaid application form (available at the office or download from dss.virginia.gov/benefit_programs/msp.html)."
            },
            {
              "step": 4,
              "title": "Submit application in person or by mail",
              "description": "Bring or mail the completed application and documents to your local DSS office."
            }
          ],
          "processingTime": "Typically 45 days",
          "waitlist": "QI program may have waitlists due to limited federal funding",
          "tip": "Apply for QMB first if income qualifies — it provides the most comprehensive coverage and has priority over other programs.",
          "urls": [
            {
              "label": "Medicare Savings Programs - Virginia DSS",
              "url": "https://www.dss.virginia.gov/benefit_programs/msp.html"
            },
            {
              "label": "Find Local DSS Office",
              "url": "https://www.dss.virginia.gov/localagency"
            }
          ]
        },
        "contentSections": [
          {
            "type": "tier-comparison",
            "heading": "Program Tiers",
            "tiers": [
              {
                "name": "QMB (Qualified Medicare Beneficiary)",
                "description": "Most comprehensive coverage",
                "incomeLimit": "Up to $1,350/month (single), $1,824/month (couple)",
                "coverage": "All Medicare Part A premiums, Part B premiums, deductibles, coinsurance, and copays"
              },
              {
                "name": "SLMB (Specified Low-Income Medicare Beneficiary)",
                "description": "Part B premium help only",
                "incomeLimit": "Higher than QMB up to ~$1,620/month (single)",
                "coverage": "Medicare Part B premiums only (~$1,980/year savings)"
              },
              {
                "name": "QI (Qualifying Individual)",
                "description": "Part B premium help with potential waitlist",
                "incomeLimit": "Higher than SLMB up to ~$1,823/month (single)",
                "coverage": "Medicare Part B premiums only (~$1,980/year savings)"
              }
            ]
          },
          {
            "type": "what-counts",
            "heading": "Asset Limits: What Counts",
            "included": [
              "Checking and savings accounts",
              "Stocks, bonds, and investment accounts",
              "Certificates of deposit",
              "Cash value of life insurance over $1,500"
            ],
            "excluded": [
              "Primary home (no equity limit)",
              "One vehicle of any value",
              "Burial plot and burial space",
              "Up to $3,500 set aside for burial expenses",
              "Household goods and personal belongings"
            ]
          },
          {
            "type": "documents",
            "heading": "What to Bring",
            "categories": [
              {
                "name": "Identity & Residency",
                "items": [
                  "Birth certificate or passport",
                  "Social Security card",
                  "Proof of Virginia residency (utility bill, lease)"
                ]
              },
              {
                "name": "Medicare",
                "items": [
                  "Medicare card showing Part A and Part B coverage",
                  "Social Security award letters"
                ]
              },
              {
                "name": "Financial",
                "items": [
                  "Bank statements from last 3 months",
                  "Stock and bond statements",
                  "Burial fund statements (if claiming exclusion)",
                  "Pay stubs if still working"
                ]
              }
            ]
          },
          {
            "type": "callout",
            "tone": "warning",
            "text": "QI program has limited federal funding and uses a first-come, first-served waitlist. If your parent's income qualifies for multiple programs, apply for QMB or SLMB first as they have guaranteed funding."
          },
          {
            "type": "callout",
            "tone": "tip",
            "text": "Income and asset limits change every January with federal poverty level adjustments. If your parent was previously denied, they may qualify now with updated limits — contact your local DSS office to verify current figures."
          }
        ],
        "faqs": [
          {
            "question": "Can my parent keep their house and car if they qualify?",
            "answer": "Yes. The primary home has no equity limit and one vehicle of any value is completely exempt from asset counting."
          },
          {
            "question": "What if Mom's income is just over the QMB limit?",
            "answer": "She may still qualify for SLMB (up to ~$1,620/month) or QI (up to ~$1,823/month) which both cover Medicare Part B premiums worth about $1,980/year. Virginia may also disregard certain types of income."
          },
          {
            "question": "Will doctors still bill my parent for Medicare costs if they have QMB?",
            "answer": "No. Providers are prohibited from billing QMB enrollees for any Medicare cost-sharing. Your parent just needs to show their Medicaid card along with their Medicare card at appointments."
          },
          {
            "question": "Does qualifying for this affect other benefits my parent receives?",
            "answer": "No, it typically helps. Your parent automatically qualifies for Extra Help with prescription drug costs and may become eligible for other programs. It doesn't reduce Social Security or other benefits."
          },
          {
            "question": "How long does the application take and when do benefits start?",
            "answer": "Applications typically take 45 days to process. If approved, benefits can be retroactive to the month of application, and Virginia will pay back any Medicare costs your parent paid during that time."
          },
          {
            "question": "What happens if my parent's income changes after they're approved?",
            "answer": "Report income changes to your local DSS office promptly. Small increases may not affect eligibility, but large changes could. They'll reassess annually, and your parent may move between program tiers based on new income."
          }
        ],
        "phone": "855-635-4370",
        "sourceUrl": "https://www.dss.virginia.gov/benefit_programs/msp.html",
        "contentStatus": "pipeline-draft",
        "draftedAt": "2026-04-09"
      }
